  "inlineSchema": "// This is your Prisma schema file,\n// learn more about it in the docs: https://pris.ly/d/prisma-schema\n\n// Get a free hosted Postgres database in seconds: `npx create-db`\n\ngenerator client {\n  provider = \"prisma-client\"\n  output   = \"../generated/prisma\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n}\n\n// Tambahkan Enum baru untuk menyelaraskan dengan status webhook Midtrans\nenum PaymentStatus {\n  PENDING\n  SETTLEMENT // Pembayaran berhasil\n  EXPIRE // Waktu bayar habis\n  CANCEL // Dibatalkan pengguna/sistem\n  DENY // Ditolak oleh fraud detection Midtrans\n  REFUND // Dana dikembalikan\n}\n\n// Enum untuk membatasi nilai yang valid pada sistem\nenum Role {\n  ADMIN\n  FAMILY // Akun keluarga yang memesan\n  NURSE // Perawat / Caregiver\n}\n\nenum ServiceType {\n  VISIT\n  LIVE_IN\n  LIVE_OUT\n}\n\nenum AppointmentStatus {\n  PENDING\n  CONFIRMED\n  ONGOING\n  COMPLETED\n  CANCELLED\n}\n\nenum ServiceName {\n  MEDIS\n  NON_MEDIS\n}\n\n// Model utama untuk autentikasi dan otorisasi pengguna\nmodel User {\n  id           String   @id @default(uuid())\n  email        String   @unique\n  passwordHash String\n  fullName     String\n  phoneNumber  String\n  role         Role     @default(FAMILY)\n  createdAt    DateTime @default(now())\n  updatedAt    DateTime @updatedAt\n\n  // Relasi: Satu akun keluarga bisa memiliki banyak data lansia\n  patients Patient[]\n\n  // Relasi: Jika user adalah perawat, dia memiliki profil khusus\n  nurseProfile NurseProfile?\n}\n\n// Model untuk data lansia yang dirawat\nmodel Patient {\n  id             String   @id @default(uuid())\n  familyId       String\n  family         User     @relation(fields: [familyId], references: [id])\n  name           String\n  dateOfBirth    DateTime\n  weight         Float?\n  height         Float?\n  medicalHistory String? // Kondisi bawaan (diabetes, hipertensi, dll)\n  createdAt      DateTime @default(now())\n  updatedAt      DateTime @updatedAt\n\n  appointments Appointment[]\n  medicalLogs  CareLog[]\n}\n\n// Model untuk melengkapi portofolio dan rating perawat\nmodel NurseProfile {\n  id              String  @id @default(uuid())\n  userId          String  @unique\n  user            User    @relation(fields: [userId], references: [id])\n  specialization  String // Contoh: \"Perawatan Luka Gangren\", \"Caregiver ADL\"\n  experienceYears Int\n  rating          Float   @default(0.0)\n  isVerified      Boolean @default(false)\n\n  appointments Appointment[]\n  careLogs     CareLog[]\n}\n\n// Model transaksi dan penjadwalan layanan\nmodel Appointment {\n  id        String       @id @default(uuid())\n  patientId String\n  patient   Patient      @relation(fields: [patientId], references: [id])\n  nurseId   String\n  nurse     NurseProfile @relation(fields: [nurseId], references: [id])\n\n  serviceType ServiceType\n  serviceName ServiceName\n  status      AppointmentStatus @default(PENDING)\n\n  // Properti ini mendefinisikan batas waktu atau tenggat pelaksanaan layanan.\n  // Didefinisikan secara eksplisit tanpa tanda tanya (?) agar mandatory (wajib diisi/tidak mungkin kosong) \n  // saat sebuah record pemesanan baru dibuat di sistem.\n  dueDate    DateTime\n  totalPrice Float\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  careLogs CareLog[]\n\n  // Relasi ke tabel pembayaran\n  payments Payment[]\n}\n\n// Model baru khusus untuk melacak riwayat pembayaran Midtrans\nmodel Payment {\n  id String @id @default(uuid())\n\n  // Relasi ke Appointment\n  appointmentId String\n  appointment   Appointment @relation(fields: [appointmentId], references: [id])\n\n  // WAJIB: Ini yang Anda kirimkan sebagai 'order_id' saat hit API Midtrans.\n  // Jangan gunakan appointmentId, gunakan paymentId (atau midtransOrderId ini)\n  midtransOrderId String @unique\n\n  amount Float\n  status PaymentStatus @default(PENDING)\n\n  // Menyimpan cara bayar (misal: \"bca_va\", \"gopay\", \"credit_card\")\n  // Diisi setelah webhook Midtrans masuk\n  paymentMethod String?\n\n  // Opsional namun direkomendasikan jika Anda menggunakan Midtrans Snap\n  // Berguna untuk me-render halaman pembayaran di frontend\n  snapToken       String?\n  snapRedirectUrl String?\n\n  paidAt    DateTime? // Waktu pasti kapan uang masuk\n  createdAt DateTime  @default(now())\n  updatedAt DateTime  @updatedAt\n\n  @@index([appointmentId])\n}\n\n// Model untuk fitur \"Laporan Digital Real-time\" dan checklist harian\nmodel CareLog {\n  id String @id @default(uuid())\n\n  // Relasi Data\n  appointmentId String\n  appointment   Appointment @relation(fields: [appointmentId], references: [id])\n\n  patientId String\n  patient   Patient @relation(fields: [patientId], references: [id])\n\n  nurseId String\n  nurse   NurseProfile @relation(fields: [nurseId], references: [id])\n\n  // Metrik Vital (Opsional / Nullable)\n  systolic    Int? // Tekanan darah atas (misal: 120)\n  diastolic   Int? // Tekanan darah bawah (misal: 80)\n  bloodSugar  Float? // Gula darah dalam mg/dL\n  cholesterol Float? // Kolesterol dalam mg/dL\n  uricAcid    Float? // Asam urat dalam mg/dL\n\n  // Observasi Klinis & Psikologis\n  woundCondition String? // Observasi dari item \"Cek Luka Jatuh\"\n  moodScore      Int? // Skala 1-5 untuk grafik mood pasien\n  clinicalNotes  String? @db.Text // Menggunakan db.Text untuk memfasilitasi catatan panjang perawat\n\n  // Log aktivitas perawat\n  activityLog ActivityLog[]\n\n  // Timestamp\n  recordedAt DateTime @default(now())\n  updatedAt  DateTime @updatedAt\n\n  // Indexing untuk performa kueri grafik\n  @@index([patientId, recordedAt])\n}\n\nmodel ActivityLog {\n  id        String   @id @default(uuid())\n  notes     String   @db.Text\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  careLogId String\n  careLog   CareLog @relation(fields: [careLogId], references: [id])\n}\n",
